final:
module top_module(
    input clk,
    input rst,
    output reg [2:0] count
);reg [2:0] unused_next_count;

always @ (posedge clk) begin
    if (rst) begin
        count <= 3'b0;
    end
    else begin
        count <= unused_next_count;
    end
end

always @ (*) begin
    case (count)
        3'b000: unused_next_count = 3'b001;
        3'b001: unused_next_count = 3'b010;
        3'b010: unused_next_count = 3'b011;
        3'b011: unused_next_count = 3'b100;
        3'b100: unused_next_count = 3'b101;
        3'b101: unused_next_count = 3'b110;
        3'b110: unused_next_count = 3'b111;
        3'b111: unused_next_count = 3'b000;
        default: unused_next_count = 3'b0;
    endcase
end

endmodule
